<script>
import SearchResult from './SearchResult.vue';

export default {
  name: 'Search',
  components: { SearchResult },
  props: {
    currentStep: { type: Number, default: -1 },
    signs: { // JSON 데이터를 받는 props
      type: Array,
      default: () => [],
    },
    selection: {
      type: Object,
      default: function () {
        return {
          start: 0,
          end: 1,
        };
      },
    },
    duration: { type: Number, default: 0 },
  },
  data() {
    return {
      durationOfSelectionString: '',
      requestedSearch: false,
      staleResults: true,
    };
  },
  computed: {
    preparedResults() {
      // 각 segment에서 상위 7개 결과만 추출
      return this.signs.map((segment) => ({
        startTime: segment[0], // 시작 시간
        endTime: segment[1], // 종료 시간
        predictions: segment[2]
      }));
    },
  },
  methods: {
    resetResults() {
      this.requestedSearch = false;
    },
    filterSigns() {
      this.requestedSearch = true;
      this.staleResults = false;

      this.durationOfSelectionString = `${
        Math.round(this.selection.start * this.duration * 10) / 10
      } and ${
        Math.round(this.selection.end * this.duration * 10) / 10
      } seconds`;

      console.log('Filtered results:', this.preparedResults);
    },
  },
  watch: {
    selection: function (newVal, oldVal) {
      if (newVal.start != oldVal.start || newVal.end != oldVal.end) {
        this.staleResults = true;
      }
    },
  },
};
</script>

